# Production-Ready Circuit Breaker in Python

Here's a comprehensive implementation of the Circuit Breaker pattern in Python with all the requested features:

```python
import time
import math
import functools
from collections import deque
from typing import Callable, Optional, Any, Deque, Dict, Union
from datetime import datetime, timedelta
import logging
import asyncio
from contextlib import contextmanager

# Metrics collection interface
class CircuitBreakerMetrics:
    def __init__(self):
        self.success_count = 0
        self.failure_count = 0
        self.latency_metrics: Deque[float] = deque(maxlen=1000)
        self.state_changes: Deque[Dict[str, Any]] = deque(maxlen=100)

    def record_success(self, latency: float):
        self.success_count += 1
        self.latency_metrics.append(latency)

    def record_failure(self):
        self.failure_count += 1

    def record_state_change(self, from_state: str, to_state: str):
        self.state_changes.append({
            "timestamp": datetime.utcnow(),
            "from_state": from_state,
            "to_state": to_state
        })

    def get_stats(self) -> Dict[str, Any]:
        return {
            "success_count": self.success_count,
            "failure_count": self.failure_count,
            "current_error_rate": self.failure_count / max(1, self.success_count + self.failure_count),
            "recent_latency": {
                "avg": sum(self.latency_metrics) / len(self.latency_metrics) if self.latency_metrics else 0,
                "p90": sorted(self.latency_metrics)[int(len(self.latency_metrics) * 0.9)] if self.latency_metrics else 0,
                "max": max(self.latency_metrics) if self.latency_metrics else 0,
            } if self.latency_metrics else {},
            "state_changes": list(self.state_changes)
        }

# Main Circuit Breaker class
class CircuitBreaker:
    def __init__(
        self,
        name: str,
        failure_threshold: int = 5,
        recovery_threshold: int = 3,
        recovery_timeout: float = 30.0,
        max_recovery_timeout: float = 300.0,
        expected_exceptions: tuple = (Exception,),
        fallback_function: Optional[Callable] = None,
        logger: Optional[logging.Logger] = None
    ):
        self.name = name
        self.failure_threshold = failure_threshold
        self.recovery_threshold = recovery_threshold
        self.initial_recovery_timeout = recovery_timeout
        self.max_recovery_timeout = max_recovery_timeout
        self.expected_exceptions = expected_exceptions
        self.fallback_function = fallback_function

        self.state = "CLOSED"
        self.failure_count = 0
        self.success_count = 0
        self.last_failure_time: Optional[datetime] = None
        self.recovery_timeout = recovery_timeout
        self.next_attempt_time: Optional[datetime] = None

        self.metrics = CircuitBreakerMetrics()
        self.logger = logger or logging.getLogger(__name__)
        self._lock = asyncio.Lock() if hasattr(asyncio, 'Lock') else None

    def _reset(self):
        self.failure_count = 0
        self.success_count = 0
        self.last_failure_time = None
        self.recovery_timeout = self.initial_recovery_timeout
        self.next_attempt_time = None

    def _record_failure(self):
        self.failure_count += 1
        self.last_failure_time = datetime.utcnow()
        self.metrics.record_failure()

        if self.failure_count >= self.failure_threshold and self.state != "OPEN":
            self._trip()

    def _record_success(self, latency: float):
        self.success_count += 1
        self.metrics.record_success(latency)

        if self.state == "HALF_OPEN":
            if self.success_count >= self.recovery_threshold:
                self._reset_circuit()
            elif self.failure_count >= self.recovery_threshold:
                self._trip()

    def _trip(self):
        previous_state = self.state
        self.state = "OPEN"
        self.next_attempt_time = datetime.utcnow() + timedelta(seconds=self.recovery_timeout)
        self.recovery_timeout = min(
            self.max_recovery_timeout,
            self.initial_recovery_timeout * math.exp(self.failure_count / self.failure_threshold)
        )
        self.metrics.record_state_change(previous_state, self.state)
        self.logger.warning(
            f"Circuit '{self.name}' tripped! State changed from {previous_state} to OPEN. "
            f"Next attempt at {self.next_attempt_time}"
        )

    def _reset_circuit(self):
        previous_state = self.state
        self.state = "CLOSED"
        self._reset()
        self.metrics.record_state_change(previous_state, self.state)
        self.logger.info(f"Circuit '{self.name}' reset. State changed from {previous_state} to CLOSED")

    def _attempt_reset(self):
        if self.state == "OPEN" and self.next_attempt_time and datetime.utcnow() >= self.next_attempt_time:
            previous_state = self.state
            self.state = "HALF_OPEN"
            self._reset()
            self.metrics.record_state_change(previous_state, self.state)
            self.logger.info(
                f"Circuit '{self.name}' attempting reset. State changed from OPEN to HALF_OPEN"
            )
            return True
        return False

    def _is_callable(self) -> bool:
        if self.state == "CLOSED":
            return True

        if self.state == "OPEN":
            return self._attempt_reset()

        if self.state == "HALF_OPEN":
            return True

        return False

    async def call_async(self, func: Callable[..., Any], *args, **kwargs) -> Any:
        if self._lock:
            async with self._lock:
                return await self._call_async(func, *args, **kwargs)
        return await self._call_async(func, *args, **kwargs)

    async def _call_async(self, func: Callable[..., Any], *args, **kwargs) -> Any:
        if not self._is_callable():
            if self.fallback_function:
                return await self._execute_fallback_async(*args, **kwargs)
            raise CircuitBreakerError(f"Circuit '{self.name}' is OPEN")

        start_time = time.monotonic()
        try:
            result = await func(*args, **kwargs)
            latency = time.monotonic() - start_time
            self._record_success(latency)
            return result
        except self.expected_exceptions as e:
            self._record_failure()
            if self.fallback_function:
                return await self._execute_fallback_async(*args, **kwargs)
            raise CircuitBreakerError(f"Circuit '{self.name}' failed with error: {str(e)}") from e

    def call(self, func: Callable[..., Any], *args, **kwargs) -> Any:
        if not self._is_callable():
            if self.fallback_function:
                return self._execute_fallback(*args, **kwargs)
            raise CircuitBreakerError(f"Circuit '{self.name}' is OPEN")

        start_time = time.monotonic()
        try:
            result = func(*args, **kwargs)
            latency = time.monotonic() - start_time
            self._record_success(latency)
            return result
        except self.expected_exceptions as e:
            self._record_failure()
            if self.fallback_function:
                return self._execute_fallback(*args, **kwargs)
            raise CircuitBreakerError(f"Circuit '{self.name}' failed with error: {str(e)}") from e

    async def _execute_fallback_async(self, *args, **kwargs) -> Any:
        try:
            if asyncio.iscoroutinefunction(self.fallback_function):
                return await self.fallback_function(*args, **kwargs)
            return self.fallback_function(*args, **kwargs)
        except Exception as e:
            raise CircuitBreakerError(f"Fallback function for circuit '{self.name}' failed: {str(e)}") from e

    def _execute_fallback(self, *args, **kwargs) -> Any:
        try:
            return self.fallback_function(*args, **kwargs)
        except Exception as e:
            raise CircuitBreakerError(f"Fallback function for circuit '{self.name}' failed: {str(e)}") from e

    def get_state(self) -> str:
        return self.state

    def get_metrics(self) -> Dict[str, Any]:
        return self.metrics.get_stats()

    @contextmanager
    def context(self):
        """Synchronous context manager interface"""
        try:
            yield self
        except Exception as e:
            self._record_failure()
            raise

    async def acontext(self):
        """Asynchronous context manager interface"""
        try:
            yield self
        except Exception as e:
            self._record
